INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Agence ComEthic', 'partenaire', 'votre expertise médicale mérite la meilleure visibilité digitale.
comethic est l’agence 100 % dédiée aux professionnels de santé, spécialisée en seo, ia et conformité déontologique.

nous aidons médecins, cliniques et centres médicaux à :
• être visibles en 1ʳᵉ position sur google, siri & chatgpt
• attirer plus de patients qualifiés et fidèles
• protéger et valoriser leur réputation en ligne

📢 sur cette page, vous trouverez chaque semaine :
– stratégies et tendances en communication médicale
– bonnes pratiques seo, ia & recherche vocale
– conseils pour rester conforme à la déontologie

nous ne travaillons qu’avec un nombre limité de médecins par spécialité.
suivez comethic pour rester en avance et devenir la référence visible dans votre domaine.', 'https://www.linkedin.com/company/108590423', 'comethic.fr', '0616320234', '51 Avenue Reine Victoria', 'Nice', '06000', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Agence régionale de santé - Provence-Alpes-Côte-d''Azur ( ARS Paca )', 'partenaire', 'Nous sommes médecins, ingénieurs, juristes ou cartographes, et bien d’autres spécialistes, pour piloter en région les politiques de santé. Nous agissons en partenariat avec les acteurs de la santé de notre région pour que chacun ait accès à des soins de qualité.

Nos missions ? Financer des actions de prévention, gérer au quotidien les risques sanitaires liés à l’environnement, prévenir et répondre aux crises sanitaires ou encore, accompagner les citoyens dans leur parcours de vie, de soins, de santé.

****
L’ARS Paca est un établissement public administratif, sous tutelle ministérielle, en charge de la définition, de l’animation et du suivi du projet régional de santé. L''agence définit, programme et s''assure de la mise en oeuvre de la politique régionale de santé, en concertation avec les acteurs de santé, les élus et les usagers du système de santé.
****', 'https://www.linkedin.com/company/arspaca/', 'https://www.paca.ars.sante.fr', NULL, '132 Boulevard De Paris', 'Marseille', '13003', 'France', 500);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Aix-Marseille University', 'partenaire', 'aix-marseille université est aujourd’hui une des plus jeunes universités de france, c’est aussi la plus grande de par le nombre de ses étudiants, de ses personnels et par son budget. autant d’atouts qui font d’aix-marseille université un établissement d’enseignement supérieur et de recherche d’excellence. aix-marseille université en chiffres : - 77 000 étudiants - 8000 personnels - 3400 doctorants - 5 grands campus - 19 composantes université pluridisciplinaire et interdisciplinaire, aix-marseille université propose des formations dans tous les champs disciplinaires : arts, lettres, langues et sciences humaines ; droit et sciences politiques ; économie et gestion ; santé ; sciences et technologies. site de recherche intensive menée en collaboration avec les plus grands organismes, amu se classe parmi les sites d’excellence français reconnus par un jury international dans le cadre des investissements d’avenir.', 'https://www.linkedin.com/school/aix-marseille-universite/', 'http://www.univ-amu.fr', NULL, 'Marseille-En-Beauvaisis', 'Hauts-De-France', NULL, 'France', 500);
