INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Binhas Global Dental School', 'partenaire', 'le binhas global dental school propose aux chirurgiens-dentistes et aux spécialistes des solutions innovantes dans les domaines de la gestion, du management, de l''organisation et de la communication. 

les résultats de nos programmes sont une diminution du stress, un accroissement de la rentabilité tout en améliorant la qualité de travail. depuis 15 ans de façon continue, nos consultants accompagnent les praticiens et leurs équipes dans l''optimisation de la gestion globale de leurs cabinets.

nous proposons des programmes innovants de consulting, de formation ou de coaching basés sur les besoins individuels de chaque praticien. années après années, plusieurs centaines de praticiens ont déjà fait confiance au groupe edmond binhas comme partenaire de leur carrière.', 'https://www.linkedin.com/company/groupebinhas/', 'bgds.fr', '0617656352 / 0617656371', '6 Rue Catulle Mendès', 'Paris', '75017', 'France', 50);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Biotech Dental', 'partenaire', 'Since its creation in 1987, Biotech Dental has been committed to building a trusting and lasting relationship with dental surgeons and dental technicians.
Together, we design and develop a range of product that is continually more adapted to the challenges of the future. We have positioned ourselves at the crossroads of our customers’ expectations, innovation and technology.

Giving dentists the ability to suggest the best products at the best price to their patients is Biotech Dental’s first objective. With more than 2 million dental implants sold, we have improved the lives of thousands of patients worldwide thanks to all the dental surgeons who trust us. Driven by our expertise and know-how, we have chosen to be pioneers of this development through innovative technologies.
In recent years, we have integrated new skills, invested over 10 % of our turnover in research and development to be able to develop and propose solutions on the cutting edge of innovation.

Biotech Dental is a privileged partner for dental practitioners. Our wide range of products and services provides an added value to answer all their patient’s needs.

Make excellence and innovation affordable is an integral part of Biotech Dental vision. All our services and products enhance the dental office 4.0.', 'https://www.linkedin.com/company/biotech-dental/', 'http://www.biotech-dental.com', NULL, '305 Allées De Craponne', 'Salon-De-Provence', '13300', 'France', 500);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Biton', 'partenaire', 'bit on consultores es una empresa desarrolladora de software  para la gestión empresarial, que desempeña su actividad desde 1998, y acreditada como business partner de ibm, esker y kofax.

nuestro equipo, formado por técnicos cualificados, aportan su conocimiento y experiencia en la reingeniería de procesos y el desarrollo de software para entornos ibm as400, wintel y plataformas web.

nuestras soluciones incorporan las últimas tendencias de mercado, permitiendo la correcta integración con erps y manteniendo los más rigurosos estándares de seguridad de la información. todo nuestro portafolio de soluciones está disponible para trabajar en la nube (saas).

la adaptabilidad de nuestros productos nos permite contar con clientes de diversos sectores de negocio, tales como empresas de logística, distribución y manufactura', 'linkedin.com/company/biton-consultores', 'biton.es', NULL, '66 Calle De Mandri', 'Barcelona', '08022', 'Spain', 50);
