INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Cara Santé', 'partenaire', 'cara santé a ouvert deux centres de santé au coeur de marseille afin de donner la possibilité à tous de se soigner et de garantir l’accès à une médecine de qualité. 
