INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Changer d''Ère - Podcast', 'partenaire', 'bienvenue dans changer d’ère, le podcast qui explore le monde en transition et t’apporte des clés et des inspirations pour agir et trouver ta place.

vous le ressentez certainement, on traverse une période unique dans notre histoire, une véritable renaissance où tout est remis en question et où tout se transforme. 
on peut se sentir un peu perdus, mais c''est aussi notre plus grande opportunité : celle de façonner une civilisation plus consciente et plus juste.

je m’appelle clément, je suis entrepreneur, et avec we are one - la communauté de leaders engagés à faire émerger cette civilisation  - nous t''invitons à explorer et entrer dans ce nouveau monde.

nous partons à la rencontre de celles et ceux qui imaginent et créent ce futur : pour comprendre cette transition, t’aider à trouver ta voie, et pour partager des clés pour agir.

notre objectif ? t''offrir des idées concrètes, des outils pour agir et des shots d''espoir sur les futurs que nous pouvons créer ensemble.

alors prêt à changer d’ère?

n''hésite pas à m''écrire à clement.dubois@hotmail.com.  

merci pour ton écoute 💚 

clément

un grand merci à veronique anger-de friberg qui a donné son autorisation pour l''utilisation de la marque "changer d''ere", inspiré du forum changer d''ere, un événement de prospective unique.', 'https://www.linkedin.com/company/changerdere-podcast/', NULL, '604157154', NULL, NULL, NULL, NULL, 10);
