INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Comex40 Bouches-du-Rhône', 'partenaire', 'le comex40 du medef est composé d’une nouvelle génération de 45 jeunes chefs d’entreprises (23 femmes et 22 hommes, issus des fédérations professionnelles et des medef territoriaux, ainsi que de personnalités extérieures).
organe non statutaire, rattaché à la présidence du medef, il a pour objectif de réfléchir, avec un œil neuf, aux grands enjeux sociétaux en anticipant leurs impacts sur les entreprises, illustrant la volonté du président geoffroy roux de bézieux d’incarner un medef de propositions.

le comex40 se réunit plusieurs fois par an en sessions plénières et à de multiples reprises à l’occasion d’ateliers, de rencontres ou de groupes de travail. 
il a pour volonté de sortir des sentiers battus et de proposer des idées neuves sur les grands enjeux du moment auxquels est confrontée l’entreprise. 
le comex40 formule également des propositions sur des saisines ponctuelles du président, interagit et débat avec des personnalités extérieures et des influenceurs, et contribue à renforcer les liens et les synergies au sein du réseau.', 'https://www.linkedin.com/company/comex40-bouches-du-rhone/', NULL, NULL, 'Marseille-En-Beauvaisis', 'Hauts-De-France', NULL, 'France', 50);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('CompuGroup Medical France', 'partenaire', 'compugroup medical is one of the leading ehealth companies in the world. with a revenue base of more than eur 550 million, its software products are designed to support all medical and organizational activities in doctors’ offices, pharmacies, laboratories and hospitals. its information services for all parties involved in the healthcare system and its web-based personal health records contribute towards safer and more efficient healthcare. compugroup medical’s services are based on a unique customer base of approximately 400,000 doctors, dentists, pharmacists and other service providers in inpatient and outpatient facilities. with locations in 20 countries and products in more than 40 countries worldwide, compugroup medical is the ehealth company with one of the highest coverage among ehealth service providers. approximately 4,500 highly qualified employees support customers with innovative solutions for the steadily growing demands of the healthcare system.', 'https://www.linkedin.com/company/compugroup-medical-france/', NULL, NULL, '55 Avenue Des Champs Pierreux', 'Nanterre', '92000', 'France', 50);
