INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('DocCity', 'partenaire', 'FACILITER LA SANTE…

… POUR LES MEDECINS

Ouvrir des espaces santé nouvelle génération, modernes, design, digitaux, accompagnés des services nécessaires à la qualité de l’exercice des métiers de santé au quotidien.

Considérer comme décisif le bien-être des Professionnels de santé : en matière de conditions de consultation, en matière d’environnement de pratique et en matière d’offre de services.
Avec comme mission finale, de réinventer l’expérience médecin / patient.

… POUR LES PATIENTS

Améliorer l’accès à des soins de qualité en regroupant sous le même toit toutes les étapes du parcours de soins.
Améliorer la lisibilité des parcours, en regroupant les professionnels par thématiques : Institut Médical du Sport Santé, Institut Médical du Poids, , Pôle Mère Enfant, Cardiologie, Ophtalmologie, Spécialités chirurgicales…
Accompagner les patients en les sensibilisant à la prévention primaire, et en les accompagnant médicalement vers une meilleure hygiène de vie.

… POUR LES BIOTECHS

Faciliter le succès des entreprises innovantes en Santé.

Améliorer l’efficacité des Biotech en mettant à leur disposition des bureaux, des espaces de coworking et des laboratoires spécialisés (L1 et L2 et en leur permettant de bénéficier de plateformes technologiques et de services partagés.

Faciliter la recherche en proposant aux biotechs un écosystème unique grâce à la proximité immédiate d’hôpitaux, de médecins, et de patients.', 'https://www.linkedin.com/company/doccity', 'http://www.doccity.fr', NULL, 'Paris', 'Île-De-France', NULL, 'France', 50);
