INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Enosis Santé', 'partenaire', 'L’association Enosis Santé a été créée en 2022 par 4 pôles de compétitivité français en santé répartis sur le territoire : BioValley France, Eurobiomed, Lyonbiopôle Auvergne-Rhône-Alpes et Medicen Paris Region. 
Par le renforcement des synergies entre eux, Enosis Santé vise à consolider leur capacité à accélérer conjointement et territorialement le développement de l’innovation healthtech, à accompagner les entreprises et les projets innovants en santé et contribuer ainsi à amplifier le leadership de la France en matière de santé.', 'https://www.linkedin.com/company/enosis-sant%C3%A9/', 'https://enosis-sante.fr/', NULL, NULL, NULL, NULL, NULL, 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Eugenol', 'partenaire', 'Depuis 1999, le site Eugenol (créé initialement sous le nom Abcdent) administré par des confrères et des professionnels de la santé, diffuse sur Internet les programmes de formation continue en médecine bucco-dentaire permettant aux professionnels du monde dentaire de s''informer sur un cours, un congrès ou un cycle annuel dans la discipline de son choix.

Eugenol est aujourd''hui le leader incontesté en ligne pour les professionnels du monde dentaire, avec notamment son forum de discussion de grande audience ( https://forum.eugenol.com ).', 'https://www.linkedin.com/company/eugenol', 'https://www.eugenol.com', NULL, '72 Avenue Parmentier', 'Paris', '75011', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Eurobiomed', 'partenaire', 'eurobiomed est le pôle de compétitivité de la filière santé regroupant les régions provence alpes côte d''azur et languedoc-roussillon. 

crée le 1er janvier 2009, le pôle a été reconnu comme un pôle très performant suite à l’audit réalisé en 2012 par l’état, les résultats sont au rendez-vous en nombre et montants de projets financés, croissance du chiffre d’affaires, croissance à l’export, emplois directs créés et maintenus par les entreprises membres.

le territoire d’eurobiomed constitue une grande région européenne de la santé, il se situe également au second rang national pour la densité de la recherche publique.

dans un contexte de forte compétition internationale, le caractère attractif d’un territoire pour les industries de santé, est particulièrement lié à l’excellence de la recherche académique. sur les filières visées, eurobiomed se distingue à l’échelle internationale par la qualité de la recherche, et par son tissu industriel parmi les plus denses en europe. 

avec un réseau de plus de 400 entreprises, majoritairement des pme innovantes, 8 universités et de nombreuses écoles formant 39000 étudiants, 400 laboratoires de recherche, 4 chu et une direction inter régionale des recherches cliniques, le cluster eurobiomed se positionne au rang des principaux clusters français et européens en santé en termes de nombre d''entreprises, de capacités de recherche et d''excellence scientifique et d''équipements dédiés à l''innovation et à la création d''entreprises innovante.', 'https://www.linkedin.com/company/eurobiomed/', 'https://www.eurobiomed.org/', NULL, '1682 Rue De La Valsière Cap Sigma', 'Montpellier', '34090', 'France', 50);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('EUROS', 'partenaire', 'créée en 1989 par loïc piclet, l''aventure commence par la prothèse plm (tige fémorale) suivi par le rachis, le genou et l’épaule au cours des 10 années suivantes.
intégrant tous les métiers au sein de notre siège social dans le sud de la france, nous maîtrisons toutes les étapes de création de produits et services : conception, industrialisation, affaires réglementaires, production et distribution. cette transversalité assure à nos clients une grande réactivité, de la flexibilité et une adaptabilité à leurs besoins.

la gamme euros s’est étendue à travers nos cinq gammes de produits (hanche, genou, rachis, épaule, et cheville/pied) pour arriver aujourd’hui à une étendue comptant plus de 25 produits.

la qualité est au centre de notre stratégie. cette culture historique nous assure aujourd’hui une croissance sereine dans un environnement réglementaire de plus en plus exigeant.

l’actionnariat familial permet à euros de grandir tout en gardant une vision humaine.

bienvenue chez euros !


founded in 1989 by loïc piclet, the history of euros began with the creation of the plm implants (femoral stem) for the hip, followed by spine, knee and shoulder implants within the next 10 years.
integrating all the functions within our headquarters in the south of france, we manage all stages of products and services: design, industrialisation, regulation, production and distribution. this cross-competence ensures responsiveness, flexibility and adaptability to the needs of our clients.

euros’ range of medical devices has expanded across five main categories (hip, knee, spine, shoulder and foot/ankle), now representing more than 25.

quality is central to our strategy. this focus today guarantees us a qualified and trustworthy growth in an increasingly demanding regulatory environment.

family shareholding enables euros to grow while preserving a human perspective.

welcome to euros !', 'https://www.linkedin.com/company/euros-sas/', 'euros.fr', NULL, 'La Ciotat', 'Provence-Alpes-Côte d''Azur', '13600', 'France', 250);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Expansi', 'partenaire', 'une structure qui regroupe des professionnels de l’expertise-comptable et du commissariat au compte et des avocats, et qui propose une offre complète de services et conseils au service des entreprises. #spe

tourné vers les besoins actuels de l’entrepreneur, dans un environnement digitalisé et en constante mutation, nous vous accompagnons dans l’ensemble de vos projets professionnels.

