INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('FEIMA Editeurs', 'partenaire', 'la fédération des editeurs d’informatique médicale et paramédicale ambulatoire (feima) regroupe les principaux éditeurs de logiciels du secteur libéral de la santé. 
les solutions et les services d’accompagnement et de support qu’ils portent équipent plus de 300 000 professionnels de santé en france (2 millions dans le monde) : médecins généralistes et spécialistes, dentistes, pharmaciens, auxiliaires médicaux, structures d’exercice pluriprofessionnel et prestataires de santé à domicile (plus de 80% du marché ambulatoire français).
acteurs industriels de premier plan (plus de 2 500 salariés en france et plus de 12 000 dans le monde), les membres de la feima constituent un levier de création d’emploi, de valeur et d’innovation de premier plan sur le marché du numérique en santé, en france et en europe.

organigramme :
président : @francis mambrini
vice-président collège médecins : dany huppenoire
vice-président collège pharmaciens : denis supplisson
vice-président collège paramédicaux : jean pierre issartel
vice-président collège dentistes : didier robert
trésorier : vincent bouvier', 'https://www.linkedin.com/company/feima-editeurs/', 'feima.fr', NULL, '55 Avenue Des Champs Pierreux Nanterre Cedex', 'Nanterre', '92012', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('France Biotech', 'partenaire', 'created in 1997, the association is the french non-profit organization that brings together the country''s leading innovative health compagnies and their expert partners (investors, lawyers, research institutes, cluster, etc...). its core mission is to promote health innovation in france and help the sector''s start-up companies and smes to become tomorrow''s leaders able to rapidly develop new therapeutic solutions.

our missions:
to support innovative start-ups and smes of the healthtech industry (biotech, medtech, digital health, big data) by tackling four major issues:

- financial: encourage investment in health innovation
- tax: ensure fiscal stability
- administrative and regulatory: facilitate clinical trials, health data access...
- cultural: promote technology transfer, public/private collaborations

our goals: 
- life sciences community networking (newsletter, conferences, experience sharing...)
- think tank (working groups, publications, white papers...)
- health institutions and government point of contact

why join us?
- to reinforce the french healthtech environnement
- to benefit from a free and exclusive access to our conferences, events and 
  publications.
- to enhance your visibility
- to develop your network by meeting entrepreneurs and experts of the healthtech 
   industry.
- and more...', 'https://www.linkedin.com/company/france-biotech/', 'france-biotech.fr', NULL, '10 Rue d''Oradour-Sur-Glane', 'Paris', '75015', 'France', 10);
