INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Hairdex', 'partenaire', 'hairdex is a french telehealth platform dedicated to men suffering from hairloss (androgenetic alopecia). we connect men to licensed healthcare professionals, enabling people to access high-quality medical care - from hairloss treaments to hair transplants.

we created hairdex to help men regain control of their hair :

💊 treatments : ultra-personalized treatment plans prescribed by a doctor, delivered to your home every 3 months (including finasteride & minxidil).

💉 transplants : definition of the online grafting project by an expert and connection with the most suitable surgeon.

📊 scan : tracking the effectiveness of a treatment through trichoscopy (ai scalp scan).', 'linkedin.com/company/hairdex', 'hairdex.fr', NULL, '153 Cours Lieutaud', 'Marseille', '13006', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Henry Schein One', 'partenaire', 'we’re henry schein one—the leader in all things dental technology. our vision? we empower dentists to focus on patient care, ensuring practice success.

with our simple and integrated technology, practices are finally more seamless, more efficient, and more profitable—meaning patients and practitioners are happier. with comprehensive solutions: demand generation, patient experience, practice management, revenue management, dental analytics, and clinical workflow, dental clinics will be running smoother than ever before. 

what’s in it for us? we get joy out of helping dentists unlock better outcomes for their patients and practices by empowering them to focus on what matters most: patient care. whether we’re providing clinical or operational insights, supporting dentists or front-office managers, we’re here to cheer on practices as they take operations and care to the next level.', 'https://www.linkedin.com/company/henry-schein-one/', 'henryscheinone.com', NULL, '1220 South 630 East', 'American Fork', '84003', 'United States', 500);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('HERITAGE MAGAZINE', 'partenaire', '🇬🇧 HERITAGE is a complete ecosystem for aesthetic surgeons, physicians and dermatologists. It includes a digital platform accessible to a global audience, and a premium print version distributed to industry leaders.

Our mission is clear: provide aesthetic professionals (surgeons, physicians, dermatologists and medical device campanies and manufacturers) an overview of the latest advances in products, technologies and practices.

Each issue is thus positioned as a link between the founding values of medical excellence and a dynamic industry driven by disruptive innovation.

For those involved in medical aesthetics, HERITAGE is a source of inspiration and reflection, a crossroads where the creative minds and solutions of tomorrow meet.

---

🇫🇷 HERITAGE est un écosystème complet destiné aux chirurgiens, médecins et dermatologues esthétique. Il comprend une plateforme digitale accessible à une audience mondiale ainsi qu''une version imprimée premium distribuée aux leaders de l''industrie. 

Notre mission est claire : fournir aux professionnels du secteur de l''esthétique (chirurgiens, médecins, dermatologues, laboratoires et fabricants de dispositifs médicaux) une vue d''ensemble des avancées les plus récentes en produits, technologies et pratiques.

Chaque numéro se positionne ainsi comme un trait d''union entre les valeurs fondatrices de l''excellence médicale et une industrie dynamique guidée par des innovations disruptives.

Pour les acteurs de l''esthétique médicale, HERITAGE est une source d''inspiration et de réflexion, un carrefour où se rencontrent les esprits créatifs et les solutions de demain.', 'https://www.linkedin.com/company/magazine-heritage/', 'http://www.magazine-heritage.com', '06 77 39 02 75', NULL, NULL, NULL, NULL, 10);
