INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Ignitera', 'partenaire', 'ignitera a pour mission d’accompagner les chef-fes d''entreprise ambitieux à concrétiser leur vision et à propulser leur entreprise vers de nouveaux sommets.  

la valeur de l''apport de ignitera se base sur l''expertise de ses dirigeants sébastien telouk, cédric messeguer et jean-claude tapia.

