INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Incubateur Belle de Mai', 'partenaire', 'L''Incubateur Belle de Mai est un incubateur d’entreprises innovantes liées à la recherche publique. Il accompagne des projets de créations d’entreprises innovantes 𝗗𝗲𝗲𝗽𝘁𝗲𝗰𝗵 uniquement dans le domaine des Technologies de l''Information et de la Communication (TIC) et technologies logicielles.

Installé à Marseille, sur le Pôle Média Belle de Mai, l’Incubateur Belle de Mai est un dispositif national. Il accueille et accompagne des projets sur toute la France.

Deux programmes d''incubation : 

- 𝗟𝗮 𝗠𝗮𝗻𝘂𝗳𝗮𝗰𝘁𝘂𝗿𝗲 𝟮+ : profitez de 3 mois d''accompagnement pour valider votre marché et rendre votre projet d''entreprise viable. Ce programme est gratuit grâce au co-financement du Fonds Social Européen

-  𝗟𝗲 𝟭𝟬𝟮𝟰 : profitez pendant 18-24 mois d''un accompagnement sur mesure, qui répond à vos besoins d''entrepreneur innovant. De plus, ce programme permet d''accéder à un financement pour votre projet pouvant aller jusqu''à 40 000€ 💰', 'https://www.linkedin.com/company/incubateur-belle-de-mai-software-deeptech', 'https://www.belledemai.org/', NULL, '37 Rue Guibal', 'Marseille-En-Beauvaisis', NULL, 'France', 10);
