INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Ioda consulting', 'partenaire', 'ioda consulting est un cabinet spécialisé et reconnu dans l’accompagnement des entreprises innovantes, deeptech et de croissance. grâce à une équipe mixant les profils comptables, scientifiques et financiers, et une parfaite connaissance de l’écosystème de l’innovation, le cabinet propose un accompagnement 360° autour de 3 métiers complémentaires : expertise-comptable, fiscalité de l’innovation (statut jei, crédit impôt recherche (cir), crédit impôt innovation (cii)) et recherche de financements.
