INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Kedge', 'partenaire', 'we are a french management school with 4 campuses in france (paris, bordeaux, marseille and toulon), 2 in china (shanghai, suzhou) and 4 associated campuses (avignon, bastia, bayonne, dakar). our community counts 12,000 students including 25% non-french students, 196 full-time faculty members, 44% of which are international, 300 international academic partners and over 50,000 alumni across the world. we deliver 31 programmes in management for students and executives, but also develop customised educational programmes for specific corporate needs worldwide. we are proud to be ranked #33 european business schools and #22 emba worldwide by the financial times. we are aacsb, equis and amba accredited and member of the french conférence des grandes écoles.', 'linkedin.com/company/kedge-business-school', 'https://entrepreneurship.kedge.edu/', NULL, '680 Cours De La Libération', 'Talence', '33400', 'France', 500);
