INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('La metropôle Aix-Marseille-Provence', 'partenaire', 'la métropole aix-marseille-provence est unique. créée par la loi maptam, elle réunit 92 communes réparties sur trois départements. elle rassemble sur un même territoire des espaces agricoles, urbains et industriels. attractive et dynamique, la métropole exerce les compétences stratégiques majeures qui déterminent le développement du territoire dans toutes ses dimensions : développement et aménagement économique, social et culturel, aménagement de l’espace métropolitain, politique locale de l’habitat, politique de la ville, gestion des services d’intérêt collectif, protection et mise en valeur de l’environnement et politique du cadre de vie.

pour accompagner son développement et ses projets, la métropole aix-marseille-provence recherche des collaborateurs désireux de s’investir dans la construction d’une collectivité innovante.', 'linkedin.com/company/métropole-aix-marseille-provence', 'https://innovation.ampmetropole.fr/participation/252/4-les-appels-a-innovation.htm?access=1&tab=1019', NULL, '58 Boulevard Charles Livon Marseille', 'Marseille-En-Beauvaisis', '13007', 'France', 500);
