INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Marseille Innovation', 'partenaire', 'Marseille Innovation, accélérateur de croissance !

