INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Mediaco vrac', 'partenaire', 'créé en 1988, mediaco vrac se développe d’abord dans le stockage vrac liquide sur marseille-fos et sète puis dans l’industrie avec la création de provence huiles. en 2008, provence huiles acquiert auprès de i.c.i la plus grosse distillerie d’amérique du sud et devient ainsi leader mondial de l’huile de pépin de raisin.
depuis 1999, le groupe développe une activité d’entreposage et gère aujourd’hui plus de 100 000m2 d’entrepôts sur vitrolles, le havre et sur la zone d’activités de distriport (marseille -fos-sur-mer).
nos racines familiales nous conduisent à un développement responsable de nos activités. nous produisons de la vapeur à partir de biomasse et de l’énergie solaire en utilisant les toitures des entrepôts.

www.mediacovrac.fr
