INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Métropole Aix-Marseille-Provence', 'partenaire', 'La Métropole Aix-Marseille-Provence est unique. Créée par la loi MAPTAM, elle réunit 92 communes réparties sur trois départements. Elle rassemble sur un même territoire des espaces agricoles, urbains et industriels. Attractive et dynamique, la Métropole exerce les compétences stratégiques majeures qui déterminent le développement du territoire dans toutes ses dimensions : développement et aménagement économique, social et culturel, aménagement de l’espace métropolitain, politique locale de l’habitat, politique de la ville, gestion des services d’intérêt collectif, protection et mise en valeur de l’environnement et politique du cadre de vie.

Pour accompagner son développement et ses projets, la Métropole Aix-Marseille-Provence recherche des collaborateurs désireux de s’investir dans la construction d’une collectivité innovante.', 'https://www.linkedin.com/company/m%C3%A9tropole-aix-marseille-provence/', 'https://www.ampmetropole.fr/', NULL, '58 Boulevard Charles Livon Marseille', 'Marseille-En-Beauvaisis', '13007', 'France', 500);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Monaco Active Technology', 'partenaire', 'nos solutions de financement locatif 

vous souhaitez renouveler votre matériel, innover, développer, conquérir, économiser, prévoir, optimiser et anticiper ... 

la location financière est une solution 
incontournable de l''investissement des entreprises 
et des professionnels. 

elle permet un financement souple dans lequel l''accent est mis sur l''usage du matériel, ses évolutions et les services qui peuvent y être associés. cette solution est une opération qui met en relation un utilisateur, son fournisseur et son bailleur. 

découvrez une stratégie gagnante sur le long terme qui permettra de vous différencier de vos concurrents avec des outils ou des machines toujours performantes et innovantes. vous pouvez ainsi solidifier les valeurs disponibles de votre entreprise tout en étant performant et rassurant pour vos partenaires et salariés. 

trésorerie,
capacité d’endettement préservée
vous ne faites pas d’avance sur la tva et la notion d’endettement n’est pas impactée, ce qui vous permettra d’investir sur des futurs projets.

solution évolutive
avec monaco active technology vous avez la possibilité de modifier le périmètre des équipements financés en cours de contrat avec une option d’évolution de votre matériel à tout moment.

simplification administrative et comptable
les investissements financés en location sont jugés hors bilan donc il n’y a pas d’immobilisation comptable.

solution souple et globale
vous pouvez choisir :

vos échéances (mensuelles, trimestrielles, etc.)
votre paiement (linéaire, progressif, dégressif, décalé, etc.)
les assurances (facultatif)', 'https://www.linkedin.com/company/monaco-active-technology/', 'mat.mc', NULL, '9 Bis Boulevard De Belgique', 'Monaco', '98002', 'Monaco', 50);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('MyOS Partners', 'partenaire', 'myos propose une offre autour de 3 piliers : 
 
pilier 1 : les problématiques fréquemment rencontrées :
 
  > gagner ses premiers clients
  > conquérir le marché des "pragmatiques"
  > créer votre sales machine
  > raccourcir le cycle de vente 
  > relancer une croissance en berne
  > créer un business model créateur de valeur
  > décliner l''offre sur d''autres marchés 
  > bâtir une organisation conçue pour grandir
  > réduire le churn
 
pilier 2 : les temps forts autour de vos levées de fonds :

  > préparation de la levée de fonds.

  > déploiement du« go to market » post levée : 
             
        . animation de la carte de stratégie 
        . formation à la vente de l''offre 
        . construction de la machine à leads 
        . dispositif de « chasse » 
        . coaching des équipes autour de 3 deals 
        . mise en place des kpis
        . pitch commercial
        . organisation des équipes "revenues"
        . bibliothèque commerciale 
        . delivery & processus

pilier 3 : les fondamentaux de votre développement

  > audit du "go to market"
  > la proposition de valeur 
  > stratégie : marché(s), client(s), offre & pricing 
  > le business model et le p&l n et n+1
  > lead gen / chasse : processus & messaging 
  > le pitch commercial
  > le processus de vente & pipe idéal
  > "sales document" : scénarios de discussion 
     + scripts + supports
  > organisation commerciale & ratios 
  > staffing : fiches de postes, 
     chasse, évaluation et recrutement
  > delivery, parcours client & processus
  > operating model et « scalabilité »', 'https://www.linkedin.com/company/myos-partners/', NULL, NULL, '107 Rue La Fayette', 'Paris', '75010', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('OPHTANEO', 'partenaire', 'ophtaneo conseille et accompagne les médecins libéraux et cabinets de groupe dans l''évolution, l''optimisation et le développement de leurs activités médicales et chirurgicales.  nous intervenons en véritable partenaire sur les différents pôles de compétences nécessaires à une prise en charge de qualité du patient en ophtalmologie.', 'linkedin.com/company/ophtaneo', 'https://ophtaneo.com/', NULL, '170 Avenue Du Pastré', 'Aubagne', '13400', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('PariSanté Campus', 'partenaire', 'PariSanté Campus vise à créer un ensemble cohérent et synergique d''opérateurs publics et privés, avec pour ambition de structurer une filière de recherche et d''innovation en santé numérique de rayonnement mondial. Cet ensemble aura vocation à s’installer sur le site de l’ancien hôpital d’instruction des armées du Val-de-Grâce, et à créer un réseau de partenariats franciliens, nationaux et internationaux. L’ensemble sera financé par des investissements inédits issus du plan de relance, et aura vocation a être un vecteur majeur de création de valeur médico scientifique, mais aussi économique. Reposant sur un chaine complète allant de la formation et de la recherche à l’innovation et la création de startups, il s’appuie en premier lieu sur l’Inserm, l’Université PSL, Inria, le Health Data Hub, et l’Agence du Numérique en Santé.', 'https://www.linkedin.com/company/parisant%C3%A9-campus/', 'https://parisantecampus.fr/', NULL, '10 Rue d''Oradour-Sur-Glane', 'Paris', '75015', 'France', 500);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Pixpay', 'partenaire', '“l’argent ça tombe pas du ciel”, “t’as cru que j’étais crésus ?”, “t’es un vrai panier percé”. 

