INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Unicancer', 'partenaire', 'unicancer groups together the 20 french comprehensive cancer centres (fcccs) which are private, not-for-profit hospitals located across the french territory. fcccs are dedicated to fighting cancer through a threefold mission of patient care, research and education. they contribute to the public hospital service in accordance with statutory fees, with no additional charge. 
unicancer is one of the largest cancer care and research organisations in europe. 

via its r&d department, it sponsors clinical trials to improve cancer patients’ care and access to innovation, particularly in areas neglected by the pharmaceutical industry.

unicancer is accredited by the french ministry of health and is eligible for public grants. 

the french comprehensive cancer centres in numbers: 
•	20 sites located throughout the french territory
•	19,000 employees
•	>135,000 patients hospitalised each year 
•	approximately 500 active clinical trials
•	17% of the patients treated are included in a clinical trial (vs an average of 8.5% of cancer patients in france)
•	19 molecular biology platforms certified by the french national cancer institute
•	7 integrated cancerology research sites (siric) certified by the french nci (out of 8)
•	12 early-phase clinical trial centres (clip²) certified by the french nci (out of 16)
•	5th for global publications in oncology
•	32% of french publications in oncology (articles in which fcccs have participated)

unicancer sponsors
•	76 ongoing clinical trials (2016)
•	including 5400 patients (2016)
•	from 270 investigator sites (2015), 
•	with 20% located in other european countries', 'https://www.linkedin.com/company/unicancer/', 'http://www.unicancer.fr', NULL, '101 Rue De Tolbiac', 'Paris', '75013', 'France', 250);
