INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('YELO DENTAL', 'partenaire', 'yelo dental, c’est l’histoire de deux grands professionnels des espaces dentaires avec plus de 20 ans d’expérience dans la livraison de projets et l’accompagnement des praticiens au service de leur métier.

l’un est passé maitre dans l’art de comprendre les souhaits et les exigences propres à chaque praticien et de l’accompagner depuis l’idée jusqu’à la réalisation de son cabinet, dans le respect des multiples normes, des délais et des investissements inhérents à chaque projet. des projets maitrisés, livrés à temps et des clients satisfaits, c’est un vrai savoir-faire. l’autre a acquis une expertise technique connue et reconnue par les praticiens qui lui permet de maitriser le fonctionnement d’équipements exigeants et d’identifier très vite la résolution des pannes et dysfonctionnements, offrant ainsi qualité, sécurité et réactivité à des clients qui ont besoin de disposer des meilleurs outils parfaitement opérationnels.

avec la passion et le professionnalisme qui les caractérisent, ils décident en 2020 d’associer leurs talents et créent yelo dental dont la marque de fabrique a été saluée unanimement par le marché : en pleine pandémie, ce sont des dizaines d’espaces dentaires qui ont vu le jour et des centaines de fauteuils installés avec succès.

choisir yelo dental, c’est aujourd’hui s’attacher les services de toute une équipe réactive, à vos côtés dans chaque étape, et animée par l’exigence de vous satisfaire : offrez-vous la sécurité et la garantie de voir votre projet livré à temps sans mauvaise surprise, disposez des équipements les plus performants, prêts et fonctionnels pour exercer sereinement.', 'https://www.linkedin.com/company/yelo-dental/', 'yelodental.com', NULL, '3 Avenue Du Fort', 'Montrouge', '92120', 'France', 10);
INSERT INTO public.companies ("name", "type", "description", "linkedin_url", "website", "phone_number", "address", "city", "zipcode", "country", "size") VALUES ('Ze Box (CMA CGM)', 'partenaire', 'zebox  is  a  global  startup  accelerator  gathering  a  network  of  entrepreneurs,  industry leaders, and ecosystem experts paving new paths toward sustainability starting with the supply chain.  
 
founded in 2018 by rodolphe saadé, chairman and ceo of cma cgm group, a global player in sea,  land,  air,  and logistics solutions.  zebox  is now supported by  20  international companies.
operating in  6  regions of the world,  zebox  provides its community with a unique set of programs, resources, and opportunities.', 'linkedin.com/company/zebox', 'https://www.cma-cgm.fr/detail-news/1908/cma-cgm-cree-a-marseille-ze-box-son-premier-incubateur-international', NULL, '61 Boulevard Des Dames', 'Lavéra', '13002', 'France', 50);
